export function buildDefaultFormFooterActions(p) {
    const prefix = p.testIdPrefix;
    return [
        {
            id: 'cancel',
            label: 'Hủy',
            variant: 'secondary',
            visible: p.cancelVisible !== false,
            onClick: p.onCancel,
            testId: `${prefix}-cancel-btn`,
        },
        {
            id: 'save',
            label: p.saving ? 'Đang lưu...' : 'Lưu',
            variant: 'primary',
            visible: p.saveVisible !== false,
            disabled: p.saving || p.saveDisabled,
            onClick: p.onSave,
            testId: `${prefix}-save-btn`,
        },
    ];
}
